import type { Metadata } from "next";
import { Geist, Geist_Mono } from "next/font/google";
import "./globals.css";
import { UserProvider } from "@/context/UserContext";
import { AccountProvider } from "@/context/AccountContext";
import { LoadingProvider } from "@/context/LoadingContext";
import { BalanceProvider } from "@/context/BalanceContext";
import { SubscriptionProvider } from "@/context/SubscriptionContext";
import { OnboardingProvider } from "@/context/OnboardingContext";
import LoadingOverlay from "@/components/LoadingOverlay";
import Footer from "@/components/organisms/Footer";
import PlanGuard from "@/components/organisms/PlanGuard";
import PaddleInit from "@/components/PaddleInit";

const geistSans = Geist({
  variable: "--font-geist-sans",
  subsets: ["latin"],
});

const geistMono = Geist_Mono({
  variable: "--font-geist-mono",
  subsets: ["latin"],
});

export const metadata: Metadata = {
  title: "TradeLab",
  description: "Trading Journal & Discipline System",
  manifest: "/manifest.json",
  icons: {
    icon: "/tradelab-logo-trans.png",
    apple: "/tradelab-logo-trans.png",
  },
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <body className={`${geistSans.variable} ${geistMono.variable} antialiased flex flex-col min-h-screen bg-slate-900`}>
        <PaddleInit />
        <LoadingProvider>
          <UserProvider>
            <SubscriptionProvider>
              <AccountProvider>
                <BalanceProvider>
                  <OnboardingProvider>
                  <PlanGuard>
                    <div className="flex-1 flex flex-col">
                      {children}
                    </div>
                    <Footer />
                    <LoadingOverlay />
                  </PlanGuard>
                  </OnboardingProvider>
                </BalanceProvider>
              </AccountProvider>
            </SubscriptionProvider>
          </UserProvider>
        </LoadingProvider>
      </body>
    </html>
  );
}

