import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

if (!supabaseUrl || !serviceRoleKey) {
  console.error('Missing Supabase env vars');
  process.exit(1);
}

const email = 'jhon.test.beta@tradelabapp.co';
const password = 'TradeLabBeta2026!';
const firstName = 'Jhon';
const lastName = 'Test';
const fullName = `${firstName} ${lastName}`;

const supabase = createClient(supabaseUrl, serviceRoleKey);

const { data: existingUsers, error: listError } = await supabase.auth.admin.listUsers({ perPage: 1000 });
if (listError) {
  console.error('Failed to list users:', listError.message);
  process.exit(1);
}

let user = existingUsers.users.find((u) => u.email?.toLowerCase() === email.toLowerCase());

if (!user) {
  const { data: created, error: createError } = await supabase.auth.admin.createUser({
    email,
    password,
    email_confirm: true,
    user_metadata: {
      full_name: fullName,
      name: fullName,
      first_name: firstName,
      last_name: lastName,
    },
  });

  if (createError) {
    console.error('Failed to create auth user:', createError.message);
    process.exit(1);
  }

  user = created.user;
}

const profilePayload = {
  id: user.id,
  first_name: firstName,
  last_name: lastName,
  plan: 'beta',
  plan_expires_at: null,
  updated_at: new Date().toISOString(),
};

const { error: upsertError } = await supabase
  .from('user_profiles')
  .upsert(profilePayload, { onConflict: 'id' });

if (upsertError) {
  console.error('Failed to upsert user profile:', upsertError.message);
  process.exit(1);
}

console.log(JSON.stringify({
  email,
  password,
  userId: user.id,
  plan: 'beta',
  created: true,
}, null, 2));

