  $list = Invoke-RestMethod -Method Get -Uri "$env:NEXT_PUBLIC_SUPABASE_URL/auth/v1/admin/users?page=1&per_page=1000" -Headers $headers
  $existing = $list.users | Where-Object { $_.email -eq $email } | Select-Object -First 1
  if ($existing) {
