"use client";

import { useEffect, useMemo, useState } from "react";
import { useUser } from "@/context/UserContext";
import { journalService, JournalEntry } from "@/services/journalService";
import { getTradingRulesAndMistakes, TradingRule } from "@/services/tradingPlanService";
import GaugeChart from "@/components/atoms/GaugeChart";
import { Flame, CheckCircle, AlertCircle, Info } from "lucide-react";

const getTradePL = (entry: JournalEntry): number => {
  if (entry.status !== "closed") return 0;
  if (typeof entry.profit_loss === "number") return entry.profit_loss;
  if (entry.exit_price && entry.entry_price && entry.quantity) {
    return entry.type === "long"
      ? (entry.exit_price - entry.entry_price) * entry.quantity
      : (entry.entry_price - entry.exit_price) * entry.quantity;
  }
  return 0;
};

// Helper to format date in local timezone (not UTC)
const toLocalYMD = (d: Date): string => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
};

interface ProgressSectionProps {
  accountId?: string;
}

export default function ProgressSection({ accountId }: ProgressSectionProps) {
  const { user } = useUser();
  const [entries, setEntries] = useState<JournalEntry[]>([]);
  const [rules, setRules] = useState<TradingRule[]>([]);
  const [mistakes, setMistakes] = useState<TradingRule[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!user) return;

    const loadData = async () => {
      setLoading(true);
      try {
        const [entriesData, rulesData] = await Promise.all([
          journalService.getEntriesByUser(user.id, accountId),
          getTradingRulesAndMistakes(user.id, "rule"),
        ]);
        setEntries(entriesData || []);
        setRules(rulesData?.filter((item) => item.type === "rule") || []);
        setMistakes(rulesData?.filter((item) => item.type === "mistake") || []);
      } catch (error) {
        console.error("Error loading progress data:", error);
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, [user, accountId]);

  const filteredEntries = useMemo(() => {
    const base = new Date();
    base.setHours(0, 0, 0, 0);
    const cutoff = new Date(base);
    cutoff.setDate(cutoff.getDate() - 28);
    const cutoffYMD = toLocalYMD(cutoff);
    
    return entries
      .filter((e) => e.status === "closed")
      .filter((e) => e.date >= cutoffYMD); // String comparison works with YYYY-MM-DD
  }, [entries]);

  const closedTradesLast28Days = filteredEntries;

  const last28Days = useMemo(() => {
    const base = new Date();
    base.setHours(0, 0, 0, 0);
    
    return Array.from({ length: 28 }, (_, i) => {
      const d = new Date(base);
      d.setDate(d.getDate() - (27 - i));
      return toLocalYMD(d);
    });
  }, []);

  // Determine current week (0-3) based on day index in 28-day cycle
  // Week 0: days 0-6, Week 1: days 7-13, Week 2: days 14-20, Week 3: days 21-27
  const getCurrentWeekIndex = () => {
    const today = toLocalYMD(new Date());
    const todayIndex = last28Days.indexOf(today);
    
    if (todayIndex === -1) return 3; // Default to last week if not found
    return Math.floor(todayIndex / 7);
  };

  const currentWeekIndex = getCurrentWeekIndex();
  const currentWeekStartIndex = currentWeekIndex * 7;
  const currentWeekEndIndex = currentWeekStartIndex + 7;

  const [mobileWeekIndex, setMobileWeekIndex] = useState(currentWeekIndex);

  const emotionalInsight = useMemo(() => {
    if (closedTradesLast28Days.length === 0) return null;

    const getComplianceRate = (dates: string[]) => {
      const dateSet = new Set(dates);
      const trades = closedTradesLast28Days.filter((t) => dateSet.has(t.date));
      if (trades.length === 0) return 0;

      const tradesWithRulesTracking = trades.filter(
        (t) => t.rules_followed !== undefined && t.rules_followed !== null && t.rules_followed !== ""
      ).length;
      const tradesFollowingRules = trades.filter(
        (t) => t.rules_followed && t.rules_followed.length > 0
      ).length;

      if (tradesWithRulesTracking > 0) {
        return Math.round((tradesFollowingRules / tradesWithRulesTracking) * 100);
      }

      const profitableTrades = trades.filter((t) => getTradePL(t) > 0).length;
      return Math.round((profitableTrades / trades.length) * 100);
    };

    const lastWeekDates = last28Days.slice(-7);
    const prevWeekDates = last28Days.slice(-14, -7);
    const lastWeekRate = getComplianceRate(lastWeekDates);
    const prevWeekRate = getComplianceRate(prevWeekDates);
    const delta = lastWeekRate - prevWeekRate;

    const weekRates = [0, 1, 2, 3].map((weekIndex) => {
      const start = weekIndex * 7;
      const end = start + 7;
      return getComplianceRate(last28Days.slice(start, end));
    });

    const bestWeekIndex = weekRates.reduce(
      (best, rate, idx) => (rate > weekRates[best] ? idx : best),
      0
    );

    if (bestWeekIndex === 3 && lastWeekRate > 0) {
      return {
        title: "Best week so far",
        subtitle: `${lastWeekRate}% rule compliance in the last 7 days`,
        tone: "text-emerald-400",
        icon: "🏅",
      };
    }

    if (delta >= 10) {
      return {
        title: "Consistency improving",
        subtitle: `+${delta}% vs previous week`,
        tone: "text-emerald-400",
        icon: "📈",
      };
    }

    if (delta <= -10) {
      return {
        title: "Rule discipline dropping this week",
        subtitle: `${delta}% vs previous week`,
        tone: "text-amber-400",
        icon: "⚠️",
      };
    }

    return {
      title: "Consistency steady",
      subtitle: "Keep your rules tight and stay patient",
      tone: "text-slate-300",
      icon: "🧭",
    };
  }, [closedTradesLast28Days, last28Days]);

  // Plan Compliance Analysis (Last 28 days)
  const planCompliance = useMemo(() => {
    if (closedTradesLast28Days.length === 0) {
      return {
        complianceRate: 0,
        goodDecisions: 0,
        improvingDays: 0,
        mistakesDetected: 0,
        profitableDaysFollowingPlan: 0,
        totalTradingDays: 0,
      };
    }

    // Group trades by day
    const tradesByDay = new Map<string, JournalEntry[]>();
    closedTradesLast28Days.forEach((trade) => {
      const list = tradesByDay.get(trade.date) || [];
      list.push(trade);
      tradesByDay.set(trade.date, list);
    });

    // Count ALL 28 days, breaking down by status
    let goodDecisionDays = 0;
    let improvingDays = 0;
    let mistakeDays = 0;
    let profitableDays = 0;

    // Process each day in last 28 days
    last28Days.forEach((date) => {
      const trades = tradesByDay.get(date) || [];

      if (trades.length === 0) {
        // No trades on this day = rest day, skip entirely
        return;
      }

      // Get trades with rules tracking
      const tradesWithTracking = trades.filter(
        (t) => t.rules_followed !== undefined && t.rules_followed !== null && t.rules_followed !== ""
      );

      if (tradesWithTracking.length === 0) {
        // Traded but didn't track rules = mistake day
        mistakeDays++;
      } else {
        // Count trades that followed rules vs didn't
        const tradesFollowedRules = tradesWithTracking.filter(
          (t) => t.rules_followed && t.rules_followed.trim().length > 0
        ).length;

        if (tradesFollowedRules === tradesWithTracking.length) {
          // All tracked trades followed rules = Good Day
          goodDecisionDays++;
        } else if (tradesFollowedRules > 0) {
          // Some tracked trades followed, some didn't = Improving Day
          improvingDays++;
        } else {
          // No tracked trades followed rules = Mistake Day
          mistakeDays++;
        }
      }

      // Check if day was profitable
      if (trades.length > 0) {
        const dayPL = trades.reduce((sum, t) => sum + getTradePL(t), 0);
        if (dayPL > 0) {
          profitableDays++;
        }
      }
    });

    // Calculate compliance rate based on tracked days
    const trackedDays = goodDecisionDays + improvingDays + mistakeDays;
    const complianceRate = trackedDays > 0 ? Math.round((goodDecisionDays / trackedDays) * 100) : 0;

    return {
      complianceRate,
      goodDecisions: goodDecisionDays,
      improvingDays,
      mistakesDetected: mistakeDays,
      profitableDaysFollowingPlan: profitableDays,
      totalTradingDays: trackedDays,

