  }, [closedTradesLast28Days, last28Days]);

  // Performance Grade
  const getGrade = (rate: number) => {
    if (rate >= 80) return { grade: "A+", color: "text-emerald-400", desc: "Excellent" };
    if (rate >= 70) return { grade: "A", color: "text-emerald-400", desc: "Very Good" };
    if (rate >= 60) return { grade: "B", color: "text-blue-400", desc: "Good" };
    if (rate >= 50) return { grade: "C", color: "text-yellow-400", desc: "Fair" };
    return { grade: "D", color: "text-red-400", desc: "Needs Improvement" };
  };

  const gradeInfo = getGrade(planCompliance.complianceRate);

  // Calculate weekly compliance for each rule
  const weeklyRulesCompliance = useMemo(() => {
    // Create compliance map for each rule
    return rules.filter(r => r.active).slice(0, 5).map(rule => {
      const dailyCompliance = last28Days.map(date => {
        const dayTrades = closedTradesLast28Days.filter(t => t.date === date);
        
        if (dayTrades.length === 0) return { status: 'no-trades', tradesCount: 0, followedCount: 0 };
        
        // Check how many trades followed this specific rule
        const tradesFollowingThisRule = dayTrades.filter(trade => {
          if (!trade.rules_followed) return false;
          const followedRules = trade.rules_followed.split(',').map(id => id.trim());
          return followedRules.includes(rule.id || '');
        }).length;
        
        // Determine status based on compliance
        let status: 'followed' | 'partial' | 'broken' = 'broken';
        if (tradesFollowingThisRule === dayTrades.length) {
          status = 'followed'; // All trades followed this rule
        } else if (tradesFollowingThisRule > 0) {
          status = 'partial'; // Some trades followed, some didn't
        }
        
        return { 
          status, 
          tradesCount: dayTrades.length, 
          followedCount: tradesFollowingThisRule 
        };
      });

      const completedDays = dailyCompliance.filter(d => d.status === 'followed').length;
      const partialDays = dailyCompliance.filter(d => d.status === 'partial').length;
      const brokenDays = dailyCompliance.filter(d => d.status === 'broken').length;
      const tradingDays = dailyCompliance.filter(d => d.status !== 'no-trades').length;
      const complianceRate = tradingDays > 0 ? Math.round((completedDays / tradingDays) * 100) : 0;
      
      return {
        rule,
        dailyCompliance,
        completedDays,
        partialDays,
        brokenDays,
        tradingDays,
        complianceRate,
        dates: last28Days
      };
    });
  }, [rules, closedTradesLast28Days]);

  // Calculate weekly mistakes tracking
  const weeklyMistakesTracking = useMemo(() => {
    // Create tracking map for each mistake
    return mistakes.filter(m => m.active).slice(0, 5).map(mistake => {
      const dailyTracking = last28Days.map(date => {
        const dayTrades = closedTradesLast28Days.filter(t => t.date === date);
        if (dayTrades.length === 0) return { status: 'no-trades', tradesCount: 0, mistakeCount: 0 };
        
        // Check how many trades made this specific mistake
        const tradesWithThisMistake = dayTrades.filter(trade => {
          if (!trade.mistakes_made) return false;
          const tradeMistakes = trade.mistakes_made.split(',').map(id => id.trim());
          return tradeMistakes.includes(mistake.id || '');
        }).length;
        
        // Determine status (inverted logic: we want to AVOID mistakes)
        let status: 'avoided' | 'partial' | 'committed' = 'avoided';
        if (tradesWithThisMistake === dayTrades.length) {
          status = 'committed'; // All trades made this mistake (BAD)
        } else if (tradesWithThisMistake > 0) {
          status = 'partial'; // Some trades made mistake, some didn't
        }
        
        return { 
          status, 
          tradesCount: dayTrades.length, 
          mistakeCount: tradesWithThisMistake 
        };
      });

      const cleanDays = dailyTracking.filter(d => d.status === 'avoided').length;
      const partialDays = dailyTracking.filter(d => d.status === 'partial').length;
      const committedDays = dailyTracking.filter(d => d.status === 'committed').length;
      const tradingDays = dailyTracking.filter(d => d.status !== 'no-trades').length;
      const improvementRate = tradingDays > 0 ? Math.round((cleanDays / tradingDays) * 100) : 0;
      
      return {
        mistake,
        dailyTracking,
        cleanDays,
        partialDays,
        committedDays,
        tradingDays,
        improvementRate,
        dates: last28Days
      };
    });
  }, [mistakes, closedTradesLast28Days]);

  return (
    <div>
      <div className="mb-8">
        <h1 className="text-2xl sm:text-4xl font-extrabold text-white mb-3">Progress</h1>
        <p className="text-slate-400 text-base">Trading Rules Compliance</p                                                                                         >
      </div>

      {loading && (
        <div className="text-center py-8">
          <p className="text-slate-400">Loading progress data...</p>
        </div>
      )}

      {!loading && (
        <div className="space-y-8">
          {emotionalInsight && (
            <div className="rounded-lg border border-slate-700 bg-slate-800/80 p-4 flex items-start gap-3">
              <div className="text-2xl leading-none">{emotionalInsight.icon}</div>
              <div>
                <p className={`text-sm font-semibold ${emotionalInsight.tone}`}>{emotionalInsight.title}</p>
                <p className="text-xs text-slate-400 mt-1">{emotionalInsight.subtitle}</p>
              </div>
            </div>
          )}
          {/* Plan Compliance Section */}
          <div className="grid grid-cols-2 lg:grid-cols-3 gap-3 lg:gap-6">
            {/* Overall Grade */}
            <div className="rounded-lg border border-slate-700 bg-slate-800 p-3 lg:p-6 text-center">
              <div className="flex items-center justify-center gap-1.5 mb-1.5 lg:mb-2">
                <p className="text-slate-400 text-xs lg:text-sm">Compliance Grade</p>
                <div className="cursor-help" title="Based on % of Good Decision days vs total tracked days">
                  <Info className="w-3 h-3 text-slate-500" />
                </div>
              </div>
              <div className={`text-4xl lg:text-5xl font-bold ${gradeInfo.color} mb-1 lg:mb-2`}>{gradeInfo.grade}</div>
              <p className="text-emerald-400 font-semibold text-xs lg:text-sm mb-0.5 lg:mb-1">{gradeInfo.desc}</p>
