              <p className="text-[10px] lg:text-xs text-slate-500 mt-1 lg:mt-2">
                {planCompliance.totalTradingDays} trading days
              </p>
            </div>

            {/* Streak */}
            <div className="rounded-lg border border-slate-700 bg-slate-800 p-3 lg:p-6 text-center">
