"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { supabase } from "@/lib/supabase/client";
import PricingPlans from "@/components/organisms/PricingPlans";
import SessionSwitchLink from "@/components/organisms/SessionSwitchLink";

export default function PlanSelectPage() {
  const router = useRouter();
  const [authed, setAuthed] = useState(false);
  const [hasSession, setHasSession] = useState(false);

  useEffect(() => {
    let mounted = true;

    supabase.auth.getSession().then(({ data }) => {
      if (!data.session) {
        router.replace("/login");
        return;
      }

      if (mounted) {
        setAuthed(true);
        setHasSession(true);
      }
    });

    const { data: listener } = supabase.auth.onAuthStateChange((_event, session) => {
      const active = Boolean(session);
      setHasSession(active);

      if (!active) {
        router.replace("/login");
      }
    });

    return () => {
      mounted = false;
      listener.subscription.unsubscribe();
    };
  }, [router]);

  if (!authed) return null;

  return (
    <PricingPlans
      ctaHref="/checkout"
      subheading="Start free for 7 days. No charge until your trial ends."
      footerAction={hasSession ? <SessionSwitchLink /> : null}
    />
  );
}

