arguments.command:
$envLines = Get-Content .env.local
foreach ($line in $envLines) { if ($line -match '^(.*?)=(.*)$') { [System.Environment]::SetEnvironmentVariable($matches[1], $matches[2]) } }
$headers = @{ 'apikey' = $env:SUPABASE_SERVICE_ROLE_KEY; 'Authorization' = "Bearer $env:SUPABASE_SERVICE_ROLE_KEY"; 'Content-Type' = 'application/json' }
try {
  $list = Invoke-RestMethod -Method Get -Uri "$env:NEXT_PUBLIC_SUPABASE_URL/auth/v1/admin/users?page=1&per_page=1000" -Headers $headers
  $profileHeaders = @{ 'apikey' = $env:SUPABASE_SERVICE_ROLE_KEY; 'Authorization' = "Bearer $env:SUPABASE_SERVICE_ROLE_KEY" }
  $profiles = Invoke-RestMethod -Method Get -Uri "$env:NEXT_PUBLIC_SUPABASE_URL/rest/v1/user_profiles?select=id,plan,first_name,last_name" -Headers $profileHeaders

  $items = foreach ($user in $list.users) {
    $profile = $profiles | Where-Object { $_.id -eq $user.id } | Select-Object -First 1
    [PSCustomObject]@{
      email = $user.email
      provider = ($user.app_metadata.provider)
      plan = if ($profile.plan) { $profile.plan } else { 'none' }
      name = ((@($profile.first_name, $profile.last_name) | Where-Object { $_ -and $_.Trim() -ne '' }) -join ' ').Trim()
      created_at = $user.created_at
    }
  }

  $items | Sort-Object created_at | ConvertTo-Json -Depth 3
} catch {
  Write-Output $_.Exception.Message
  if ($_.ErrorDetails.Message) { Write-Output $_.ErrorDetails.Message }
  exit 1
}

